import { DynamicModule, Module, Provider, FactoryProvider } from '@nestjs/common';
import { createConnection, Connection } from 'typeorm';

export interface DatabaseOptions {
  host: string;
  port: number;
  username: string;
  password: string;
  database: string;
}

export const DATABASE_CONNECTION = 'DATABASE_CONNECTION';

export class DatabaseModule {
  static forRootAsync(options: {
    useFactory: (...args: any[]) => Promise<DatabaseOptions> | DatabaseOptions;
    injects?: any[];
  }): DynamicModule {
    const connectionProvider: FactoryProvider<Promise<Connection>> = {
      provide: DATABASE_CONNECTION,
      useFactory: async (...args: any[]) => {
        const dbOptions = await options.useFactory(...args);
        return createConnection(dbOptions);
      },
      inject: options.injects || [],
    };

    return {
      module: DatabaseModule,
      providers: [connectionProvider],
      exports: [DATABASE_CONNECTION],
      global: true, // optionnel
    };
  }
}

// Utilisation dans AppModule
@Module({
  imports: [
    DatabaseModule.forRootAsync({
      injects: [ConfigService],
      useFactory: (configService: ConfigService) => ({
        host: configService.get('DB_HOST'),
        port: configService.get('DB_PORT'),
        username: configService.get('DB_USER'),
        password: configService.get('DB_PASSWORD'),
        database: configService.get('DB_NAME'),
      }),
    }),
  ],
})
export class AppModule {}
