import { DynamicModule, Module, Inject, Injectable } from '@nestjs/common';

export function getTenantConnectionToken(tenantId: string): string {
  return `DATABASE_CONNECTION_${tenantId}`;
}

export interface TenantDatabaseOptions {
  tenantId: string;
  host: string;
  port: number;
  database: string;
}

@Module({})
export class TenantDatabaseModule {
  static register(options: TenantDatabaseOptions): DynamicModule {
    const connectionToken = getTenantConnectionToken(options.tenantId);

    const connectionProvider = {
      provide: connectionToken,
      useFactory: async () => {
        const connection = await createConnection({
          name: options.tenantId, // nom unique pour TypeORM
          type: 'postgres',
          host: options.host,
          port: options.port,
          database: options.database,
        });
        return connection;
      },
    };

    return {
      module: TenantDatabaseModule,
      providers: [connectionProvider],
      exports: [connectionToken],
    };
  }
}

// Utilisation dans un module parent
@Module({
  imports: [
    TenantDatabaseModule.register({
      tenantId: 'clientA',
      host: 'db-client-a.example.com',
      port: 5432,
      database: 'client_a_db',
    }),
    TenantDatabaseModule.register({
      tenantId: 'clientB',
      host: 'db-client-b.example.com',
      port: 5432,
      database: 'client_b_db',
    }),
  ],
})
export class MultiTenantModule {}

// Injection dans un service
export class UserService {
  constructor(
    @Inject(getTenantConnectionToken('clientA'))
    private clientADb: Connection,
    @Inject(getTenantConnectionToken('clientB'))
    private clientBDb: Connection,
  ) {}
}
