import { DynamicModule, Global, Module, Injectable, Inject, OnApplicationBootstrap } from '@nestjs/common';
import axios from 'axios';

export const CONFIG_TOKEN = 'APP_CONFIG';

export interface AppConfig {
  apiUrl: string;
  maxConnections: number;
  features: string[];
}

@Injectable()
export class ConfigService {
  constructor(@Inject(CONFIG_TOKEN) private config: AppConfig) {}

  get<T = any>(key: keyof AppConfig): T {
    return this.config[key] as T;
  }
}

@Global()
@Module({})
export class ConfigModule {
  static forRootAsync(options: {
    remoteUrl: string;
    fallbackConfig?: AppConfig;
    retries?: number;
  }): DynamicModule {
    const configProvider = {
      provide: CONFIG_TOKEN,
      useFactory: async () => {
        const maxRetries = options.retries || 3;
        for (let attempt = 1; attempt <= maxRetries; attempt++) {
          try {
            const response = await axios.get<AppConfig>(options.remoteUrl, { timeout: 5000 });
            return response.data;
          } catch (error) {
            if (attempt === maxRetries) {
              if (options.fallbackConfig) {
                console.warn('API distante indisponible, utilisation de la configuration de secours');
                return options.fallbackConfig;
              }
              throw new Error(`Impossible de charger la configuration depuis ${options.remoteUrl} après ${maxRetries} tentatives`);
            }
            await new Promise(resolve => setTimeout(resolve, 1000 * attempt));
          }
        }
      },
    };

    return {
      module: ConfigModule,
      providers: [configProvider, ConfigService],
      exports: [ConfigService],
    };
  }
}

// Utilisation
@Module({
  imports: [
    ConfigModule.forRootAsync({
      remoteUrl: 'https://config.api.example.com/v1/settings',
      fallbackConfig: { apiUrl: 'http://localhost:3000', maxConnections: 10, features: ['logging'] },
      retries: 5,
    }),
  ],
})
export class AppModule {}
